var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헉…?!","JPN":"はっ……！？","ENG":"*Gasp*","TWN":"嚇……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"집이구나… 다행이다.","JPN":"家か……よかった。","ENG":"I'm home... Whew.","TWN":"我在家嗎……太好了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"매일 악몽 꾸는 것 같은데, 괜찮은 거야?","JPN":"毎日悪夢にうなされてるみたいだけど、大丈夫？","ENG":"You look like you have a nightmare every night. Are you okay?","TWN":"你好像每天都在做惡夢，沒事吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응… 어쩔 수 없지 뭐.","JPN":"ん……まあ、仕方ないよ。","ENG":"Yeah... But there's nothing I can do about it.","TWN":"是啊……但我也沒什麼好辦法。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그나저나 오늘은 고물상 일을 하는 날인데, 괜찮으면 같이 나가지 않을래?","JPN":"ところで今日は古物商の仕事をする日なんだけど、よかったら一緒に行かない？","ENG":"Anyway, today's the day I work at the junk shop. Care to tag along if it's okay with you?","TWN":"話說今天要幫破銅爛鐵店工作，瑪卡要一起來嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"보리스 아저씨한테 총기류를 고쳐주려고?","JPN":"ボリスおじさんの武器を直しに行くの？","ENG":"Are you going there to help Boris fix firearms?","TWN":"是幫布里斯大叔修理槍械嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응. 총기류도 있긴 하지만 보통 의수를 많이 맡아주곤 해.","JPN":"銃とかの武器もあるけど、普段は義肢を頼まれることが多いかな。","ENG":"Yeah. Some are firearms, but it's normally a lot of prosthetics.","TWN":"嗯。雖然也有槍械，但通常是修理義肢比較多。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"시린그라드에는 팔이나 다리를 의수로 대체하는 사람들이 많거든.","JPN":"シリングラードには腕や足を義肢にしている人が多いの。","ENG":"There are a lot of people in Ciringrad who have their limbs replaced with prosthetics.","TWN":"在錫林格勒，有很多人用義肢呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"내가 도와주지 않으면 많이 불편할 것 같아서 늘 도와드리고 있어.","JPN":"やっぱり不便そうだから、私がいつも手伝っているんだ。","ENG":"I help out because, without me, it'll be inconvenient for them.","TWN":"不好好修的話，大家會很不方便，所以我一直在幫忙。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"알았어. 그럼 내가 수레 끌어줄게.","JPN":"わかった。じゃあ私が荷車を引く。","ENG":"Okay. Then I'll pull the cart instead.","TWN":"明白了，那我來拉車吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 말 안 해도 찰떡같이 알아듣는구나!","JPN":"えへっ、察しがよくて何より！","ENG":"Hehe. You already know what to do without even me telling you!","TWN":"嘿嘿，不用說你就懂我的意思啦！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"오늘은 마을 곳곳을 돌아다녀 볼 거니까, 분명 마브카한테도 좋은 시간이 될 거야!","JPN":"今日は村のあちこちを回るから、マブカにも有意義な時間になるよ！","ENG":"Today, we're going to go around the village, so I'm sure it'll be a good time for you too, Mavka!","TWN":"今天要在村子裡到處跑，瑪卡肯定也會喜歡的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아주머니! 저 왔어요!","JPN":"おばさん！　サシャです！","ENG":"Ma'am! I'm here!","TWN":"我來了！阿姨！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"사샤구나. 마브카도 함께네?","JPN":"サシャ、いらっしゃい。マブカも一緒なのね。","ENG":"It's you, Sasha. And Mavka's with you too.","TWN":"是莎夏啊，瑪卡也一起來了嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"둘이서 수레를 끌고 다니는 모습이 정말 귀엽구나.","JPN":"二人で荷車を引いて回ってるの、とても可愛いね。","ENG":"You two look so cute pulling that cart around.","TWN":"你們兩個拉著車的樣子真可愛。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"에헤헤. 정말요?","JPN":"えへへ、本当ですか？","ENG":"Ehehe. Really?","TWN":"嘿嘿，真的嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"예전에 수리 요청하신 물건 고쳐왔어요.","JPN":"この前修理を頼まれたやつ、持って来ました。","ENG":"I'm here to fix an item you requested for repair.","TWN":"之前修理的東西已經修好了。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BREAD_DOLL_NPC_NULL","text":{"KOREA":"매번 신경 써줘서 고맙구나. 자, 보수는 여깄단다.","JPN":"いつもありがとう。さ、報酬はこちらよ。","ENG":"I appreciate you doing this every time. Here's your pay.","TWN":"每次都麻煩你了，謝謝。來，這是報酬。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BREAD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 감사합니다 아주머니!","JPN":"えへへ、ありがとうございます！","ENG":"Hehe. Thank you so much, ma'am!","TWN":"嘿嘿。謝謝阿姨！"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>물건만 두고 가시오.</color> 라고 적혀있네.","JPN":"<color=#ffd34c>モノだけおいて行きなさい</color>、って書かれてる。","ENG":"It says, <color=#ffd34c>\\"Leave the stuff here and go.\\"</color>","TWN":"上面寫著<color=#ffd34c>把東西放下就走</color>呢。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SLIDE"},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"가끔은 얼굴 좀 보여주시지.","JPN":"たまには顔見せてくれてもいいのに。","ENG":"I wish he'd show his face one day.","TWN":"偶爾也露露臉吧。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"싸우기라도 했어?","JPN":"喧嘩でもしたの？","ENG":"Did you two fight or something?","TWN":"和人吵架了嗎？"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아니. 여기 사시는 분은 아마 추방당한 분이었을 거야.","JPN":"ううん、ここの方はたぶん、追放されたんだと思う。","ENG":"No. He's just someone who was exiled from the country.","TWN":"不是，住在這裡的人應該是被驅逐的。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마음의 상처가 깊으신가 봐. 나도 거의 본 적 없거든.","JPN":"心の傷が深いんだろうね。私もほとんど顔を見たことがないの。","ENG":"I think he's pretty scarred from it. I've never seen him either.","TWN":"可能心裡的傷口很深，我也幾乎沒見過他。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"혼자서 지낸다고 나아지진 않을 텐데… 조금 걱정이야.","JPN":"一人で全部抱え込んでいても状況がよくなることはないのに……心配だなあ。","ENG":"But it won't get any better being so isolated... So I'm a little worried.","TWN":"但一個人悶著不會比較好……有點擔心呢。"},"stage":{"bg":"CIRIN_VILLAGE_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"의족을 조금 험하게 다루시는 것 같아요.","JPN":"義足の使い方が荒いんだと思います。","ENG":"You seem to really be harsh with your prosthetic leg.","TWN":"你好像對義肢有點粗暴。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"다음부턴 조심히 다녀주세요. 한번 움직여 보실래요?","JPN":"これからは動くのにもう少し注意してください。ちょっと動いてみますか？","ENG":"You should be more careful with it. Could you try moving it now?","TWN":"以後請小心點，要試著動一下嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"크헉…!","JPN":"がはっ……！","ENG":"Agh...!","TWN":"咳……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괘, 괜찮으세요?!","JPN":"だ、大丈夫ですか！？","ENG":"A-are you all right?!","TWN":"你，你沒事吧？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"제길… 움직이질 않잖아!","JPN":"くそっ……動かねえじゃねえか！","ENG":"Dammit... It won't move!","TWN":"可惡……完全沒動！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"내가 넘어지는 걸 보고 싶어서 일부러 그런 거냐?","JPN":"俺が倒れるところを見たくてわざとやったんだろ！","ENG":"Did you do that on purpose just to see my fall?","TWN":"你是故意想看我摔倒的嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그, 그렇지 않아요! 정말 죄송해요… 바로 고쳐드릴 테니까…!","JPN":"ち、違います！　本当にごめんなさい……すぐ直しますから……！","ENG":"N-no! I'm so sorry... I'll fix it right away–!","TWN":"不，不是的！真的很抱歉……我馬上替你修好……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"넌 제대로 하는 게 하나도 없어!","JPN":"こんなのもちゃんとできねえのか！","ENG":"Why can't you do anything right?!","TWN":"你到底會做什麼！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"너 때문에 내가 며칠을 폐인처럼 지내왔는지 알아!","JPN":"お前のせいで俺は何日も廃人生活をしてるんだ！　わかってんのか！","ENG":"Do you know how many days I've been like this because of you?!","TWN":"你知道因為你，我這幾天過得有多糟嗎！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤에게 해를 입힐 생각 하지마.","JPN":"サシャに危害を加えるのは許さない。","ENG":"Don't you dare think about harming Sasha.","TWN":"別想傷害莎夏。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"넌 분명…!","JPN":"お前は確か……！","ENG":"You're–!","TWN":"你是……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"괘, 괜찮아 마브카.","JPN":"だ、大丈夫だよマブカ。","ENG":"I-it's okay, Mavka.","TWN":"不，沒事的，瑪卡。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"저기… 조금만 기다려 주세요 다시 고쳐드릴게요.","JPN":"あの……やり直しますからちょっとだけ待っててください。","ENG":"Um... Just hold on and I'll fix it again.","TWN":"那個……請稍等一下，我會重新修好的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"아니, 난 못 믿겠어.","JPN":"いいや、信用できない。","ENG":"No. I don't trust you.","TWN":"不，我才不相信你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"너 설마 나한테 덤탱이 씌우려고 이러는 거 아냐?!","JPN":"お前、全部俺のせいにするつもりだろ！？","ENG":"You're trying to rip me off, aren't you?!","TWN":"你又想來坑我對吧？！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"네?! 아니에요! 전 그저….","JPN":"え！？　違います！　私はただ……","ENG":"What?! No! I was just–","TWN":"啊？不是！我只是……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"제길… 이래서 이런 고아한테 맡기는 게 아니었는데!","JPN":"くそ……こんな孤児に任せるんじゃなかった！","ENG":"Dammit... I should've never let an orphan touch it!","TWN":"可惡……早知道就不該把這件事交給一個孤兒！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"당신. 방금 그 말 취소해.","JPN":"ちょっと、今の言葉は撤回して。","ENG":"Hey. You take that back.","TWN":"你，把剛才的話收回去。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"네가 뭐 어쩔 거지? 북방군 동료들이라도 부를 거냐?","JPN":"できないと言ったらどうする？　北方軍の仲間でも呼んでくるのか？","ENG":"What are you gonna do about it? Are you going to call your Northern Army comrades?","TWN":"你想怎樣？叫你那些北方軍的同夥來嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"네 소문은 이미 시린그라드에 다 퍼졌어. 모두 널 탐탁지 않게 여긴다고.","JPN":"お前の噂はシリングラード全土に広まってるんだ。皆お前の存在を気味悪いと思ってるぞ。","ENG":"Your rumor has already spread throughout Ciringrad. Everyone here doesn't like you.","TWN":"你的事情已經傳遍錫林格勒了，沒有人會喜歡你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"당장은 잘해주는 것 같지? 조금만 수틀리면 어떻게든 널 죽이려 들걸?","JPN":"今は普通に接してもらえてるんだろうな。でも何かあったらすぐ殺しにかかはずだ。","ENG":"You think they're being nice to you now, right? But I bet it'll only take one wrong move for them to try and kill you!","TWN":"只是現在看起來對你還不錯吧？只要你敢輕舉妄動，他們就會殺了你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"너도 마찬가지야 사샤. 또 거지 시절로 돌아가고 싶지 않으면…!","JPN":"お前もだよ、サシャ。また浮浪生活に戻りたくないなら……！","ENG":"That goes the same for you, Sasha. If you don't want to be out on the streets again–!","TWN":"你也是一樣，莎夏。如果不想回到大街上當乞丐……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"걱정하지 마라. 그럴 일은 없으니까.","JPN":"そんなことにはならないから心配するな。","ENG":"Don't worry about that. Because it will never happen.","TWN":"別擔心，不會發生這種事。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"아, 안드레이…!","JPN":"ア、アンドレイ……！","ENG":"A-Andrei...!","TWN":"安，安德烈……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"여전히 한심한 짓이나 하고 돌아다니는군.","JPN":"相変わらず情けないことをやってるな。","ENG":"I see you're still going about acting like a loser.","TWN":"你還在做這些無聊的事啊。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"이 아이들을 탐탁지 않게 생각하는 건, 이 마을에서 너뿐인 것 같은데?","JPN":"この子たちを気に入らないと思ってるのは、この村でお前だけのように見えるが。","ENG":"But it seems that you're the only one in this village who doesn't like these two, hmm?","TWN":"好像只有你一個人不喜歡這兩個孩子吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"길게 말할 생각 없다. 꺼져.","JPN":"長話しをするつもりはない。失せろ。","ENG":"I don't want to waste my breath on you. Get lost.","TWN":"我不想多說，滾。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLD_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COLD_DOLL_NPC_NULL","text":{"KOREA":"제길…!","JPN":"くそ……！","ENG":"Dammit...!","TWN":"可惡……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"앗, 가버리셨네.","JPN":"あっ、行っちゃった。","ENG":"Oh, he left.","TWN":"啊，走掉了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"굳이 쫓지 마라. 저런 놈한텐 과분한 대우야.","JPN":"追わなくていい。あんなやつによくしてやる必要はない。","ENG":"Don't bother chasing after him. He's not worth it.","TWN":"不用追了，那種傢伙不值得。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"마브카였지? 온 지 얼마 안 됐는데, 지저분한걸 보게 된 것 같군.","JPN":"マブカ。村に来たばかりなのに、汚いところを見せてしまったな。","ENG":"Mavka, right? I'm sorry you had to see that mess when you've only been here for a couple of days.","TWN":"你說你叫瑪卡是吧？才剛來不久就看到這些黑暗面。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……더한 것도 많이 봐왔는걸.","JPN":"……もっと酷いものも見てきた。","ENG":"...I've seen worse.","TWN":"……更糟的我也見過很多。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"또 만났네 아저씨.","JPN":"また会えたね、おじさん。","ENG":"Hello again.","TWN":"又見面了，大叔。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"사샤에게 들었겠지만, 여긴 북방합의체의 유배지나 다름없는 마을이다.","JPN":"サシャに聞いてると思うが、ここは北方合意体の流刑地のような村だ。","ENG":"I'm sure Sasha told you already, but this place is where the banished people of the Northern Union have gathered.","TWN":"你應該從莎夏那裡聽說過，這裡和北方和議會的邊疆地帶沒什麼兩樣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"험한 사람들이 많으니 조심히 지내는 게 좋을 거다.","JPN":"気性の荒いやつらが多いから気をつけた方がいいだろう。","ENG":"Best be careful as there are a lot of dangerous people.","TWN":"有很多危險的人，所以最好小心點。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"감싸주셔서 고마워요 아저씨!","JPN":"庇ってくれてありがとう、おじさん。","ENG":"Thank you for protecting us, Andrei!","TWN":"大叔，謝謝你保護我！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"신경 쓰지 마라.","JPN":"気にするな。","ENG":"Don't mention it.","TWN":"別在意。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"휴우~ 겨우 다 돌았네. 마브카가 도와줘서 엄청 편했어.","JPN":"ふう～やっと全部回れたね。マブカが手伝ってくれたおかげで助かったよ。","ENG":"Phew! And we're done. It was a lot easier because you helped me out, Mavka.","TWN":"呼～終於忙完了。多虧了瑪卡幫忙，輕鬆了很多。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"아이고 피곤해라… 씻는 것도 귀찮으니까 이대로 자야겠다.","JPN":"疲れた……風呂も面倒くさいし、このまま寝ようと。","ENG":"I'm beat... I'm too tired to wash, so I think I'll just sleep like this.","TWN":"哎呀，好累啊……連澡都懶得洗了，就這樣睡吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"흠냐… 내일은 한가하니까 좀 많이 자둬야지…","JPN":"むにゃむにゃ……明日は暇だからぐっすり寝よう……","ENG":"*Yawn* I got nothing tomorrow, so I will get a lot of sleep...","TWN":"嗯……明天很閒，可以……多睡一下……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……사샤.","JPN":"……サシャ。","ENG":"...Sasha.","TWN":"……莎夏。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응… 왜?","JPN":"ん……？　どうしたの？","ENG":"Hm...? What is it?","TWN":"嗯……怎麼了？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"오늘은 악몽 꾸지 마.","JPN":"今日は悪夢見ないでね。","ENG":"Don't have any nightmares tonight.","TWN":"今天別做噩夢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그건… 잘자라는 뜻이지?","JPN":"それは……おやすみって意味だよね？","ENG":"That's... supposed to mean, good night, right?","TWN":"那是……在說晚安嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 걱정해 줘서 고마워.","JPN":"えへへ、心配してくれてありがとう。","ENG":"Hehe. Thanks for your concern.","TWN":"嘿嘿。謝謝你的關心。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그런데 내가 자고 있을 때 마브카는 뭘 해?","JPN":"でも、私が寝てる間マブカは何をしてるの？","ENG":"Say, what do you do when I'm asleep, Mavka?","TWN":"可是我睡覺的時候，瑪卡在做什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……그냥 앉아서 이런저런 생각.","JPN":"……その辺に座って、色んなことを考えたり。","ENG":"...I just sit and think about stuff.","TWN":"……只是坐著，胡思亂想。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"이런저런 생각?","JPN":"色んなこと？","ENG":"Think about stuff?","TWN":"胡思亂想？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사실 나도 뭘 해야 되는지 모르겠어.","JPN":"正直何をすればいいか、私にもわからない。","ENG":"To be honest, I don't know what I should be doing.","TWN":"其實我也不知道該做什麼。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"한가한 시간은… 적응이 잘 안돼.","JPN":"暇な時間って……慣れてないの。","ENG":"All this free time... I can't get used to it.","TWN":"閒下來的時間……還不太習慣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"임무에 투입되지 않는 나날이 없었거든.","JPN":"今までは毎日任務に送られていたから。","ENG":"You see, there wasn't a day I wasn't on a mission.","TWN":"以前的我總是在執行任務。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사실… 잠을 잔다는 게 어떤 느낌인지, 어떻게 했는지조차 기억이 안 나.","JPN":"眠るというのがどんな感覚だったのか、昔はどうしていたのかすらもう思い出せない。","ENG":"So... I can't even remember what it feels like to sleep, or how I even did it.","TWN":"其實……我甚至不記得睡覺是什麼感覺，也不知道該怎麼入睡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카. 여기 잠깐 누워볼래?","JPN":"マブカ、ちょっとここで横になってみる？","ENG":"Mavka, would you lie down here for a moment?","TWN":"瑪卡。可以過來躺著嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그대로 눈 감고 있어. 지금부터 나랑 같이 자는 거다?","JPN":"そして目を閉じて。今から私と一緒に寝るんだよ。","ENG":"Now, close your eyes and keep them closed. You're going to sleep with me starting now, okay?","TWN":"就這樣閉上眼睛。從現在開始和我一起睡覺，好嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 잠에 들 수 없다니까.","JPN":"だから私は眠れないって。","ENG":"I told you, I can't sleep.","TWN":"我說了，我睡不著。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그럼 연습할까? 뭐든 시작이 어려운 거야.","JPN":"じゃあ練習しようか？　何事も初めは難しいもんね。","ENG":"Then how about we practice? Everything's only hard at first.","TWN":"那就練習一下嘛？萬事起頭難。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"자 빨리!","JPN":"ほら早く！","ENG":"Now, c'mon!","TWN":"快點！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L45_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"아니 그러니까 나는…!","JPN":"いや、だから私は……！","ENG":"That's not what I meant...!","TWN":"不，我是說……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"알았다니까 그러네. 빨리 눈 감아봐?","JPN":"わかってるって。早く目を閉じて見て。","ENG":"Don't worry about it. Just close your eyes, okay?","TWN":"知道了知道了，那就快點閉上眼睛？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내 말은 하나도 안 듣고 있어….","JPN":"私の話、全然聞いてない……","ENG":"You're not listening to me...","TWN":"……你真的完全沒在聽我說話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"좋아. 마음대로 해봐.","JPN":"いいよ、好きにして。","ENG":"Fine. I'll play along.","TWN":"好，那就試試吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"헤헤. 그럼 마브카가 좋은 꿈에 들 수 있도록 자장가를 불러줄게?","JPN":"えへへ、じゃあマブカがいい夢を見られるように、子守唄を歌ってあげる。","ENG":"Hehe. Do you want me to sing you a lullaby so that you can have good dreams?","TWN":"嘿嘿，那我唱首搖籃曲哄你睡，你就做個好夢吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"자기도 맨날 악몽이나 꾸면서….","JPN":"自分だって毎日うなされてるくせに……","ENG":"You're the one who's always having nightmares...","TWN":"這句話你該對自己說……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>자장… 자장… 나의 아름다운 아가.</color>","JPN":"<color=#ffd34c>眠れ…私の愛しい子よ、ねんころりん。</color>","ENG":"<color=#ffd34c>Sleep, baby, my dearest... Hushabye, a-bye.</color>","TWN":"<color=#ffd34c>睡吧……寶貝……我美麗的寶貝。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>조용한 달빛이 선명하게. 너의 요람을 비추는구나.</color>","JPN":"<color=#ffd34c>静かに見ている、明るい月が…お前の揺りかごを。</color>","ENG":"<color=#ffd34c>Quietly, the bright moon is looking at you in the cradle.</color>","TWN":"<color=#ffd34c>靜靜地，月光灑在你的搖籃上。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>동화를 들려줄게. 노랫가락을 들려줄게.</color>","JPN":"<color=#ffd34c>私の話を聞いてよ、歌を歌うよ。</color>","ENG":"<color=#ffd34c>I will tell you a story, sing you a song.</color>","TWN":"<color=#ffd34c>給你講個故事，給你把歌唱。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>너의 눈을 감고 자거라.</color>","JPN":"<color=#ffd34c>お前は眠る、瞳を閉じて…</color>","ENG":"<color=#ffd34c>You dream a dream, closing your eyes. Hushabye, a-bye.</color>","TWN":"<color=#ffd34c>閉上眼睛，睡吧。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그렇게 토닥토닥 한다고 잠들 리가….","JPN":"そうやってとんとんしても眠れるわけ……","ENG":"There's no way that I'm going to fall asleep because you're patting me...","TWN":"這樣拍拍我可不會睡著……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"마브카. 결과 보고해 줘.","JPN":"マブカ。結果を報告してくれ。","ENG":"Mavka, report.","TWN":"瑪卡，報告結果。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"임무… 완료.","JPN":"任務……完了。","ENG":"Mission... complete.","TWN":"任務……完成。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"생체반응… 없음.","JPN":"生体反応……なし。","ENG":"Biosignals... not found.","TWN":"生命反應……無。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"굉장해. 솔직히 이 정도일 줄은 몰랐어.","JPN":"すごい。正直、ここまでとは思ってなかった。","ENG":"Amazing. I didn't think you'd be this strong.","TWN":"真是太棒了。說實話你已經超出了我的預期。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_QM","text":{"KOREA":"정말 대견스럽구나 마브카. 국가의 영웅이라 불릴 날도 머지 않겠어.","JPN":"本当に素晴らしい、マブカ。国の英雄と呼ばれる日もそう遠くないだろう。","ENG":"I'm so proud of you, Mavka. You will soon be praised as a national hero.","TWN":"真了不起啊，瑪卡。你成為國家英雄的日子不遠了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};